const { Pool } = require('pg');
const pool = new Pool({ host: 'localhost', port: 5432, database: 'store', user: 'admin', password: '123456' });
const products = [ {name: 'iPhone 15 Pro', price: 5500, description: 'Apple flagship phone', stock: 15}, {name: 'iPhone 15', price: 4500, description: 'Apple phone', stock: 20}, {name: 'Samsung S24 Ultra', price: 5200, description: 'Best Samsung phone', stock: 12}, {name: 'MacBook Pro 16', price: 9500, description: 'Apple pro laptop', stock: 8}, {name: 'MacBook Air', price: 5500, description: 'Apple light laptop', stock: 15}, {name: 'AirPods Pro 2', price: 1100, description: 'Apple premium earbuds', stock: 40}, {name: 'Apple Watch Series 9', price: 1800, description: 'Apple watch', stock: 25}, {name: 'PS5', price: 2800, description: 'PlayStation 5', stock: 15}, {name: 'Nike Air Max', price: 800, description: 'Classic sneakers', stock: 30}, {name: 'Adidas Hoodie', price: 350, description: 'Comfortable hoodie', stock: 50}, {name: 'Levis Jeans', price: 400, description: 'Classic jeans', stock: 40}, {name: 'Ray-Ban Sunglasses', price: 600, description: 'Classic sunglasses', stock: 25}, {name: 'Leather Wallet', price: 200, description: 'Genuine leather wallet', stock: 60}, {name: 'Cap Black', price: 150, description: 'Stylish black cap', stock: 70}, ];
async function seed() { for (const p of products) { try { await pool.query( 'INSERT INTO products (name, price, description, stock) VALUES ($1, $2, $3, $4)', [p.name, p.price, p.description, p.stock] ); console.log('✅', p.name); } catch (e) { console.log('❌', p.name, e.message); } } console.log('🎉 Done!'); process.exit(); }
seed();